class Solution:
    def countKReducibleNumbers(self, s: str, k: int) -> int:
        MOD = 10**9 + 7
        n = int(s, 2)
        memo = {}

        def count_set_bits(x):
            return bin(x).count('1')

        def is_k_reducible(x, k):
            if x == 1:
                return True
            if k == 0:
                return False
            if (x, k) in memo:
                return memo[(x, k)]
            memo[(x, k)] = is_k_reducible(count_set_bits(x), k-1)
            return memo[(x, k)]

        count = 0
        for i in range(1, n):
            if is_k_reducible(i, k):
                count += 1
        return count % MOD
